@startuml
skinparam classAttributeIconSize 0

class Ginasio {
  nome: String
  quadra: List<Quadra>
}

abstract class Pessoa {
  nome: String
}

class Quadra {
  numero: Int
  aluguel: Aluguel
  ginasio: Ginasio
}

class Clients {
  id: Int
  nome: String
  locacao: List<Aluguel>
}

class Aluguel {
  cliente: Client
  tempo: Int
  quadra: Quadra
}

Ginasio *-- Quadra

Pessoa <|-- Clients

Quadra "1..*" -- "1" Aluguel

Clients "0..*" *-- Aluguel
@enduml
